-- VIETNAM HUDlocal Players = game:GetService("Players")local LocalPlayer = Players.LocalPlayer-- GUIlocal GUI = Instance.new("ScreenGui")GUI.Name = "VIETNAM_HUD"GUI.Parent = game.CoreGuilocal Main = Instance.new("Frame", GUI)Main.Size = UDim2.new(0,600,0,360)Main.Position = UDim2.new(0.5,-300,0.5,-180)Main.BackgroundColor3 = Color3.fromRGB(18,18,18)Main.Active = trueMain.Draggable = trueInstance.new("UICorner", Main)-- LOGO IMAGElocal Logo = Instance.new("ImageLabel", Main)Logo.Size = UDim2.new(0,40,0,40)Logo.Position = UDim2.new(0,10,0,5)Logo.BackgroundTransparency = 1Logo.Image = "rbxassetid://119597452155690"-- TITLElocal Title = Instance.new("TextLabel", Main)Title.Size = UDim2.new(1,0,0,45)Title.BackgroundTransparency = 1Title.Text = "🇻🇳 VIETNAM HUD"Title.Font = Enum.Font.GothamBoldTitle.TextSize = 22Title.TextColor3 = Color3.new(1,1,1)-- CONTAINERlocal Container = Instance.new("Frame", Main)Container.Position = UDim2.new(0,0,0,50)Container.Size = UDim2.new(1,0,1,-50)Container.BackgroundTransparency = 1local UIList = Instance.new("UIListLayout", Container)UIList.Padding = UDim.new(0,10)-- NOTIFYlocal function Notify(msg)    print("VIETNAM HUD:",msg)end-- BUTTONlocal function Button(text,callback)    local Btn = Instance.new("TextButton", Container)    Btn.Size = UDim2.new(0,220,0,40)    Btn.BackgroundColor3 = Color3.fromRGB(35,35,35)    Btn.TextColor3 = Color3.new(1,1,1)    Btn.Text = text    Btn.Font = Enum.Font.Gotham    Btn.TextSize = 16        Btn.MouseButton1Click:Connect(callback)end-- TOGGLElocal function Toggle(text,callback)    local state = false        local Btn = Instance.new("TextButton", Container)    Btn.Size = UDim2.new(0,220,0,40)    Btn.BackgroundColor3 = Color3.fromRGB(40,40,40)    Btn.TextColor3 = Color3.new(1,1,1)    Btn.Text = text.." : OFF"        Btn.MouseButton1Click:Connect(function()        state = not state        Btn.Text = text.." : "..(state and "ON" or "OFF")        callback(state)    end)end-- CHARACTERlocal function GetHum()    local char = LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait()    return char:WaitForChild("Humanoid")end-- SPEEDToggle("Chạy nhanh",function(v)    local hum = GetHum()    hum.WalkSpeed = v and 40 or 16end)-- JUMPToggle("Nhảy cao",function(v)    local hum = GetHum()    hum.JumpPower = v and 100 or 50end)-- RESETButton("Reset chỉ số",function()    local hum = GetHum()    hum.WalkSpeed = 16    hum.JumpPower = 50    Notify("Đã reset")end)-- DASHButton("Dash",function()    local char = LocalPlayer.Character    if not char then return end        local root = char:FindFirstChild("HumanoidRootPart")    if not root then return end        root.Velocity = root.CFrame.LookVector * 120end)Notify("VIETNAM HUD Loaded")
